import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';
import {
  getClient,
  getSummary,
  getTrends,
  getComparison,
  getCampaigns,
  getPlatforms
} from '../utils/api';

import { MetricCard } from '../components/MetricCard';

import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  Legend
} from 'recharts';

import {
  ArrowLeft,
  TrendingUp,
  DollarSign,
  MousePointerClick,
  Target,
  RefreshCw
} from 'lucide-react';

import toast from 'react-hot-toast';

const COLORS = [
  '#2563EB',
  '#7C3AED',
  '#059669',
  '#D97706',
  '#DC2626',
  '#0891B2'
];

const PLATFORMS = [
  'all',
  'meta',
  'google',
  'linkedin',
  'twitter',
  'tiktok',
  'other'
];

const fmt = (n, d = 0) =>
  parseFloat(n || 0).toLocaleString('en-US', {
    minimumFractionDigits: d,
    maximumFractionDigits: d
  });

const fmtCur = (n) =>
  `₹${Number(n || 0).toLocaleString('en-IN', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  })}`;

const fmtPct = (n) => `${fmt(n, 2)}%`;

const Tooltip_ = ({
  active,
  payload,
  label,
  prefix = '',
  suffix = ''
}) => {
  if (!active || !payload?.length) return null;

  return (
    <div
      style={{
        background: 'var(--bg2)',
        border: '1px solid var(--border)',
        borderRadius: 8,
        padding: '8px 12px',
        boxShadow: 'var(--shadow-md)'
      }}
    >
      <div
        style={{
          fontSize: 11,
          color: 'var(--text3)',
          marginBottom: 4
        }}
      >
        {label}
      </div>

      {payload.map((p, i) => (
        <div
          key={i}
          style={{
            fontSize: 13,
            fontWeight: 600,
            color: p.color
          }}
        >
          {p.name}: {prefix}
          {fmt(p.value, 2)}
          {suffix}
        </div>
      ))}
    </div>
  );
};

export default function ClientDetail() {
  const { id } = useParams();

  const navigate = useNavigate();

  const [client, setClient] = useState(null);
  const [summary, setSummary] = useState(null);
  const [trends, setTrends] = useState([]);
  const [comparison, setComparison] = useState(null);
  const [campaigns, setCampaigns] = useState([]);
  const [platforms, setPlatforms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [platform, setPlatform] = useState('all');
  const [activeTab, setActiveTab] = useState('overview');

  const [insights, setInsights] = useState([]);
  const [recommendations, setRecommendations] = useState([]);
  const [reportSummary, setReportSummary] = useState(null);

  const load = useCallback(() => {
    setLoading(true);

    const params = {
      platform: platform !== 'all' ? platform : undefined
    };

    Promise.all([
      getClient(id),
      getSummary(id, params),
      getTrends(id, { ...params, months: 6 }),
      getComparison(id, params),
      getCampaigns(id, params),
      getPlatforms(id, params)
    ])
      .then(([c, s, t, cmp, camp, plat]) => {
        setClient(c);
        setSummary(s);

        const byMonth = {};

        t.forEach((row) => {
          if (!byMonth[row.month]) {
            byMonth[row.month] = {
              month: row.month,
              spend: 0,
              clicks: 0,
              conversions: 0,
              impressions: 0
            };
          }

          byMonth[row.month].spend += parseFloat(row.spend || 0);
          byMonth[row.month].clicks += parseFloat(row.clicks || 0);
          byMonth[row.month].conversions += parseFloat(
            row.conversions || 0
          );
          byMonth[row.month].impressions += parseFloat(
            row.impressions || 0
          );
        });

        setTrends(
          Object.values(byMonth).sort((a, b) =>
            a.month.localeCompare(b.month)
          )
        );

        setComparison(cmp);
        setCampaigns(camp);
        setPlatforms(plat);
      })
      .catch(() => toast.error('Failed to load data'))
      .finally(() => setLoading(false));
  }, [id, platform]);

  useEffect(() => {
    load();
  }, [load]);

  useEffect(() => {
    axios
      .post(
        'https://augmetic-internship.onrender.com/api/ai-reports/analyze',
        {
          platform: 'Meta Ads',
          spend: 250000,
          revenue: 1100000,
          clicks: 4200,
          conversions: 160
        }
      )
      .then((res) => {
        setInsights(res.data.insights);
        setRecommendations(res.data.recommendations);
        setReportSummary(res.data.summary);
      })
      .catch((err) => {
        console.log(err);
      });
  }, []);

  const platformData = platforms.map((p) => ({
    name: p.platform,
    value: parseFloat(p.spend || 0)
  }));

  if (!client && !loading) {
    return (
      <div style={{ textAlign: 'center', padding: 60 }}>
        <p>Client not found</p>

        <button
          className="btn btn-primary"
          onClick={() => navigate('/clients')}
        >
          Back to Clients
        </button>
      </div>
    );
  }

  return (
    <div className="fade-in">

      {/* HEADER */}

      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          marginBottom: 24
        }}
      >
        <button
          className="btn btn-ghost btn-sm"
          onClick={() => navigate('/clients')}
        >
          <ArrowLeft size={15} />
        </button>

        <div style={{ flex: 1 }}>
          <div className="page-title">
            {client?.name || '...'}
          </div>

          <div className="page-subtitle">
            {client?.industry || 'Performance Dashboard'}
          </div>
        </div>

        <div style={{ display: 'flex', gap: 8 }}>
          <select
            className="form-select"
            style={{ width: 'auto', fontSize: 13 }}
            value={platform}
            onChange={(e) => setPlatform(e.target.value)}
          >
            {PLATFORMS.map((p) => (
              <option key={p} value={p}>
                {p === 'all'
                  ? 'All Platforms'
                  : p.charAt(0).toUpperCase() + p.slice(1)}
              </option>
            ))}
          </select>

          <button
            className="btn btn-secondary btn-sm"
            onClick={load}
          >
            <RefreshCw size={13} />
          </button>
        </div>
      </div>

      {/* EXECUTIVE BUSINESS SUMMARY */}

      <div
        className="card card-pad"
        style={{ marginBottom: 20 }}
      >
        <h2
          style={{
            marginBottom: 16,
            fontSize: 20,
            fontWeight: 700
          }}
        >
          Executive Business Summary
        </h2>

        {reportSummary && (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns:
                'repeat(auto-fit,minmax(180px,1fr))',
              gap: 16
            }}
          >
            <div>
              <div style={{ color: '#64748B' }}>
                Advertising Spend
              </div>

              <div
                style={{
                  fontSize: 24,
                  fontWeight: 700
                }}
              >
                {fmtCur(reportSummary.spend)}
              </div>
            </div>

            <div>
              <div style={{ color: '#64748B' }}>
                Revenue Generated
              </div>

              <div
                style={{
                  fontSize: 24,
                  fontWeight: 700
                }}
              >
                {fmtCur(reportSummary.revenue)}
              </div>
            </div>

            <div>
              <div style={{ color: '#64748B' }}>
                Profit Return
              </div>

              <div
                style={{
                  fontSize: 24,
                  fontWeight: 700
                }}
              >
                {reportSummary.roas?.toFixed(2)}x
              </div>
            </div>

            <div>
              <div style={{ color: '#64748B' }}>
                New Customers
              </div>

              <div
                style={{
                  fontSize: 24,
                  fontWeight: 700
                }}
              >
                {reportSummary.conversions}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* KPI CARDS */}

      <div
        className="grid grid-4"
        style={{ marginBottom: 20 }}
      >
        <MetricCard
          label="Total Spend"
          value={fmtCur(summary?.total_spend)}
          icon={DollarSign}
          color="#2563EB"
        />

        <MetricCard
          label="Impressions"
          value={fmt(summary?.total_impressions)}
          icon={TrendingUp}
          color="#7C3AED"
        />

        <MetricCard
          label="Clicks"
          value={fmt(summary?.total_clicks)}
          icon={MousePointerClick}
          color="#059669"
        />

        <MetricCard
          label="Conversions"
          value={fmt(summary?.total_conversions)}
          icon={Target}
          color="#D97706"
        />
      </div>

      {/* TRENDS */}

      <div className="card card-pad">

        <div
          style={{
            fontWeight: 700,
            fontSize: 14,
            marginBottom: 16
          }}
        >
          Monthly Spend Trend
        </div>

        <ResponsiveContainer width="100%" height={250}>
          <LineChart data={trends}>
            <XAxis dataKey="month" />

            <YAxis
              tickFormatter={(v) =>
                `₹${(v / 1000).toFixed(0)}k`
              }
            />

            <Tooltip content={<Tooltip_ prefix="₹" />} />

            <Line
              type="monotone"
              dataKey="spend"
              stroke="#2563EB"
              strokeWidth={3}
            />
          </LineChart>
        </ResponsiveContainer>
      </div>

    </div>
  );
}
